mapper.select:
SELECT id, codigo, nome, valor, marca, validade, ativo FROM produtos WHERE 1=1
AND validade BETWEEN #{dthrInicio} AND #{dthrFim}
AND LOWER(nome) LIKE CONCAT('%', LOWER(#{nome}), '%')
AND valor >= #{valorMinimo}
AND valor <= #{valorMaximo}
AND LOWER(marca) LIKE CONCAT('%', LOWER(#{marca}), '%')
AND ativo = #{ativo}
ORDER BY ${columnType} ${orderType}
